data.content:
Use a custom `HttpMessageHandler` to mock `HttpClient`, and leverage `CancellationToken` for timeout/cancellation tests:

```csharp
[TestClass]
public class DataFetcherTests
{
    // Stub handler to control HttpClient responses
    private sealed class StubHandler : HttpMessageHandler
    {
        public HttpResponseMessage Response { get; set; } = new(HttpStatusCode.OK);
        public Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>>? SendFunc { get; set; }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            return SendFunc?.Invoke(request, cancellationToken)
                ?? Task.FromResult(Response);
        }
    }

    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new StubHandler
        {
            Response = new(HttpStatusCode.OK) { Content = new StringContent("hello") }
        };
        var sut = new DataFetcher(new HttpClient(handler));

        var result = await sut.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var handler = new StubHandler { Response = new(HttpStatusCode.NotFound) };
        var sut = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => sut.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelledBeforeCall()
    {
        var handler = new StubHandler();
        var sut = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => sut.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelledDuringRequest()
    {
        var handler = new StubHandler
        {
            SendFunc = async (_, ct) =>
            {
                await Task.Delay(TimeSpan.FromSeconds(30), ct); // simulate slow server
                return new HttpResponseMessage(HttpStatusCode.OK);
            }
        };
        var sut = new DataFetcher(new HttpClient(handler));
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => sut.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // MSTest-level safety net
    public async Task FetchAsync_RespectsTimeout()
    {
        var handler = new StubHandler
        {
            SendFunc = async (_, ct) =>
            {
                await Task.Delay(Timeout.InfiniteTimeSpan, ct);
                return new HttpResponseMessage(HttpStatusCode.OK);
            }
        };
        // HttpClient.Timeout triggers cancellation internally
        var client = new HttpClient(handler) { Timeout = TimeSpan.FromMilliseconds(50) };
        var sut = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => sut.FetchAsync("https://example.com"));
    }
}
```

**Key patterns:**

- **`StubHandler`** — avoids mocking frameworks; gives full control over `HttpClient` responses and timing.
- **Pre-cancelled token** — tests the synchronous cancellation path.
- **`CancellationTokenSource(delay)`** — tests cancellation *during* an in-flight request without actually waiting.
- **`HttpClient.Timeout`** — verifies the service correctly propagates `HttpClient`'s built-in timeout (which throws `TaskCanceledException`).
- **`[Timeout(3000)]`** — MSTest safety net so a broken test doesn't hang CI indefinitely.
